const resultado = (() => {
  const sd = $getWorkflowStaticData('global');

  const updates         = $json.result || [];
  const workflowStartTs = sd.workflowStartTs || 0;
  let   maiorUpdateId   = sd.ultimoUpdateId  || 0;

  if (updates.length === 0) {
    sd.ultimoUpdateId = maiorUpdateId;
    return [];
  }

  // ── Persistência entre execuções ────────────────────────────────────────────
  if (!sd.pedidoAtivo) sd.pedidoAtivo = {};
  if (!sd.historico)   sd.historico   = {};

  // ── Banco de dados ──────────────────────────────────────────────────────────
  const pedidosDB = [
    {
