      frete: 30.00, desconto: 0, total: 399.00,
      pagamento: "PIX", parcelas: 1,
      devol: true, reemb: true, prazoDevol: 5, motCancel: null
    },
    {
      id: "CP4H7N", cliente: "Carlos Oliveira", produto: "Fone Bluetooth Premium",
      sku: "FON-BT-PRE", qtd: 1,
      status: "aguardando_pagamento", statusLabel: "Aguardando pagamento",
      etapa: "Pedido criado - pagamento pendente",
      transportadora: null, rastreio: null, urlRastreio: null,
      previsao: null, dataEnvio: null,
      dataPedido: "07/06/2026", dataEntrega: null,
      frete: 0, desconto: 0, total: 189.90,
      pagamento: "Boleto Bancário", parcelas: 1,
      devol: false, reemb: false, prazoDevol: 0, motCancel: null
    },
    {
      id: "DW6J1E", cliente: "Ana Lima", produto: "Camiseta Estampada",
      sku: "CAM-EST-M", qtd: 2,
      status: "cancelado", statusLabel: "Cancelado",
      etapa: "Pedido cancelado",
      transportadora: null, rastreio: null, urlRastreio: null,
