      etapa: "Em rota de distribuição regional",
      transportadora: "Correios PAC", rastreio: "PA556677889BR",
      urlRastreio: "https://rastreamento.correios.com.br/app/index.php?codigo=PA556677889BR",
      previsao: "14/06/2026", dataEnvio: "09/06/2026",
