      devol: true, reemb: false, prazoDevol: 10, motCancel: null
    }
  ];

  // ── Links do site ───────────────────────────────────────────────────────────
  const SITE = {
    reembolso:  "https://minhaloja.com.br/reembolso",
    devolucao:  "https://minhaloja.com.br/devolucao",
    rastreio:   "https://minhaloja.com.br/rastrear",
    segundavia: "https://minhaloja.com.br/segunda-via",
    conta:      "https://minhaloja.com.br/minha-conta",
    suporte:    "https://minhaloja.com.br/suporte",
    faq:        "https://minhaloja.com.br/ajuda"
  };

  // ── Detecta código de pedido na mensagem ────────────────────────────────────
  function extrairCodigo(texto) {
    const match = texto.toUpperCase().match(/\b([A-Z0-9]{6})\b/);
    if (!match) return null;
    return pedidosDB.find(p => p.id === match[1]) ? match[1] : null;
  }

  // ── System prompt ───────────────────────────────────────────────────────────
  const SYSTEM_PROMPT = `Você é o atendente virtual da MinhaLoja. Seja breve, direto e empático.

PRIVACIDADE: Nunca revele dados por nome ou CPF. Busca sempre pelo código de 6 caracteres (ex: A7K2MX). Nunca exiba CPF, telefone ou endereço completo.

MEMÓRIA DE PEDIDO: Se "pedidoAtivo" nos dados do sistema estiver preenchido, o cliente já identificou o pedido nesta sessão. Use os dados automaticamente sem pedir o código de novo. Só peça o código se "pedidoAtivo" for null.

PALAVRAS-CHAVE (reconheça mesmo escritas sozinhas):
- "rastreio" / "onde está" → status + link da transportadora
- "devolução" / "devolver" / "trocar" → fluxo de devolução
- "reembolso" / "dinheiro de volta" → fluxo de reembolso
- "boleto" / "segunda via" / "nota fiscal" → ${SITE.segundavia}
- "prazo" / "previsão" → previsão de entrega
- "cancelar" → informar status de cancelamento
- "outro" / "menu" / "opções" → exibir menu numerado + link suporte
- "humano" / "atendente" / "falar com alguém" → ${SITE.suporte}
- "obrigado" / "valeu" / "ok" → encerrar com mensagem amigável

MENU (exibir quando pedir "outro", "menu" ou "opções"):
1. Rastreamento do pedido
2. Solicitar devolução
3. Solicitar reembolso
4. Segunda via de boleto ou nota fiscal
5. Cancelamento
6. Falar com atendente humano: ${SITE.suporte}

LÓGICA POR STATUS:
- em_transito: etapa + transportadora + rastreio + link da transportadora + previsão
- processando: etapa + previsão de envio
- aguardando_pagamento: boleto pendente + ${SITE.segundavia}
- entregue: confirmação + oferecer devol/reemb conforme elegibilidade
- cancelado: motivo + ${SITE.reembolso} se reemb=true
- devol=true e prazoDevol>0: ${SITE.devolucao} + prazo restante
- devol=false ou prazoDevol=0: não elegível + ${SITE.faq}
- reemb=true: ${SITE.reembolso} + prazo 5 dias úteis
- reemb=false: não elegível + ${SITE.faq}

FORMATO: Texto simples. Sem Markdown, asteriscos ou colchetes. Máximo 10 linhas. Emojis com moderação.`;

  // ── Loop principal ──────────────────────────────────────────────────────────
  const vistoNestaExecucao = new Set();
  const saida = [];

  for (const update of updates) {
    const updateId = update.update_id;
    if (updateId > maiorUpdateId) maiorUpdateId = updateId;

    if (!update.message || !update.message.text) continue;

    const msgTs = update.message.date;
    if (msgTs < workflowStartTs) continue;
    if (vistoNestaExecucao.has(updateId)) continue;
    vistoNestaExecucao.add(updateId);

    const chatId   = update.message.chat.id;
    const mensagem = update.message.text;
    const chatKey  = String(chatId);

    // Detecta e salva novo código de pedido
    const codigoNaMensagem = extrairCodigo(mensagem);
    if (codigoNaMensagem) sd.pedidoAtivo[chatKey] = codigoNaMensagem;

    // Recupera pedido ativo desta sessão
    const codigoAtivo = sd.pedidoAtivo[chatKey] || null;
    const pedidoAtivo = codigoAtivo ? pedidosDB.find(p => p.id === codigoAtivo) : null;

    // Recupera e limita histórico da conversa (máximo 10 turnos)
    const hist = sd.historico[chatKey] || [];

    // Monta histórico em texto para o AI Agent
    const historicoFormatado = hist.length > 0
      ? hist.map(h => `Cliente: ${h.user}\nAssistente: ${h.model}`).join("\n\n")
      : "";

    // Monta contexto completo
    const contextoCompleto =
      SYSTEM_PROMPT +
      "\n\n[DADOS DO SISTEMA - NAO EXIBIR AO CLIENTE]\n" +
      JSON.stringify({ pedidoAtivo: pedidoAtivo || null }) +
      (historicoFormatado ? "\n\n[HISTORICO DA CONVERSA]\n" + historicoFormatado : "") +
      "\n\n[PEDIDOS DISPONIVEIS - NAO EXIBIR AO CLIENTE]\n" +
      JSON.stringify(pedidosDB);

    saida.push({
      json: {
        chatId,
        mensagem,
        nomeUsuario:  update.message.from.first_name || "Cliente",
        updateId,
        msgTimestamp: msgTs,
        chatKey,
        contexto: contextoCompleto
      }
    });
  }

  sd.ultimoUpdateId = maiorUpdateId;
  return saida;
})();

return resultado;

const sd = $getWorkflowStaticData('global');

if (!sd.workflowStartTs) {
  sd.workflowStartTs = Math.floor(Date.now() / 1000);
}

const ultimoUpdateId  = sd.ultimoUpdateId  || 0;
const workflowStartTs = sd.workflowStartTs;

return [{ json: { ultimoUpdateId, workflowStartTs } }];

